import{_ as s,o as a,c as e,ag as i}from"./chunks/framework.CO1DiHOz.js";const g=JSON.parse('{"title":"What is ra?","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/index.md","filePath":"concepts/index.md"}'),n={name:"concepts/index.md"};function r(o,t,h,l,d,p){return a(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="what-is-ra" tabindex="-1">What is ra? <a class="header-anchor" href="#what-is-ra" aria-label="Permalink to &quot;What is ra?&quot;">​</a></h1><blockquote><p><strong>ra</strong> is a <strong>r</strong>aw <strong>a</strong>gent. A <strong>r</strong>ole <strong>a</strong>gent. A <strong>r</strong>un-<strong>a</strong>nything <strong>a</strong>gent.</p><p>One binary you configure into whatever agent you need — without rewriting anything.</p></blockquote><p>Same binary. Different config. Different agent.</p><ul><li>Drop a <code>ra.config.yml</code> in a repo → a project-specific assistant with its own system prompt, skills, and tools</li><li>Set env vars → a different provider, a different persona, the same CLI</li><li>Pass <code>--skill</code> → inject a role or behavior at runtime</li><li>Run <code>--mcp</code> → expose it as a tool to Cursor, Claude Desktop, or anything MCP-aware</li></ul><h2 id="why-ra" tabindex="-1">Why ra? <a class="header-anchor" href="#why-ra" aria-label="Permalink to &quot;Why ra?&quot;">​</a></h2><p>Most AI tools are single-purpose. A CLI that can&#39;t become an API. A framework locked to one provider. A chat UI you can&#39;t automate. You end up wiring together different tools for different contexts — each with its own config, its own auth, its own quirks.</p><p>ra is one binary that adapts to where you need it.</p><h3 id="ci-caught-a-flaky-test" tabindex="-1">CI caught a flaky test <a class="header-anchor" href="#ci-caught-a-flaky-test" aria-label="Permalink to &quot;CI caught a flaky test&quot;">​</a></h3><p>Your pipeline fails at 3am. Add one step:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debugger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-output.log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Why is this test failing?&quot;</span></span></code></pre></div><p>It reads the logs, explains the root cause, and exits. Pipe the output to Slack, write it to a PR comment, or just read it in the morning.</p><h3 id="you-re-building-a-feature" tabindex="-1">You&#39;re building a feature <a class="header-anchor" href="#you-re-building-a-feature" aria-label="Permalink to &quot;You&#39;re building a feature&quot;">​</a></h3><p>Drop into the REPL and think out loud:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">›</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /attach</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/auth.ts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">›</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> should</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> limiting</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> this</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> endpoint?</span></span></code></pre></div><p>Attach files, ask follow-ups, keep context. Resume the session tomorrow with <code>/resume</code>.</p><h3 id="your-product-needs-ai" tabindex="-1">Your product needs AI <a class="header-anchor" href="#your-product-needs-ai" aria-label="Permalink to &quot;Your product needs AI&quot;">​</a></h3><p>Start a streaming API server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --http</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --http-port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3000</span></span></code></pre></div><p>POST a message, get SSE chunks back. No Express, no framework — just <code>Bun.serve()</code> under the hood.</p><h3 id="your-editor-needs-a-specialist" tabindex="-1">Your editor needs a specialist <a class="header-anchor" href="#your-editor-needs-a-specialist" aria-label="Permalink to &quot;Your editor needs a specialist&quot;">​</a></h3><p>Run ra as an MCP server and Cursor or Claude Desktop can call it directly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ra</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code-review</span></span></code></pre></div><p>Now your editor has a dedicated code reviewer that uses your project&#39;s style guide, your skills, your system prompt.</p><hr><p>Same config. Same skills. Same binary. The interface changes, the agent doesn&#39;t.</p><h2 id="what-s-in-the-box" tabindex="-1">What&#39;s in the box <a class="header-anchor" href="#what-s-in-the-box" aria-label="Permalink to &quot;What&#39;s in the box&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>REPL</strong></td><td>Interactive sessions with history</td></tr><tr><td><strong>One-shot CLI</strong></td><td>Scriptable prompts, streams to stdout</td></tr><tr><td><strong>HTTP API</strong></td><td>Sync + streaming chat, session management</td></tr><tr><td><strong>MCP client</strong></td><td>Pull tools from other MCP servers</td></tr><tr><td><strong>MCP server</strong></td><td>Expose ra as a tool to other apps</td></tr><tr><td><strong>Tool calling</strong></td><td>Model invokes functions, ra executes them</td></tr><tr><td><strong>Skills</strong></td><td>Reusable instruction bundles — roles, behaviors, and assets</td></tr><tr><td><strong>File attachments</strong></td><td>Attach files in CLI and REPL</td></tr><tr><td><strong>Session storage</strong></td><td>Persist conversations, resume later, auto-prune old ones</td></tr><tr><td><strong>Layered config</strong></td><td>File → env → CLI override order; commit a baseline, tweak per-run</td></tr></tbody></table>`,27)])])}const k=s(n,[["render",r]]);export{g as __pageData,k as default};
